mapper.select:
WITH ref_values AS ( SELECT sample_unique_id, toFloat64OrNull(alteration_value) AS ref_val FROM genetic_alteration_derived WHERE cancer_study_identifier = #{cancerStudyIdentifierA} AND profile_type = #{profileTypeA} AND hugo_gene_symbol = #{hugoGeneSymbol} AND alteration_value != '' AND alteration_value != 'NA' AND toFloat64OrNull(alteration_value) IS NOT NULL
AND sample_unique_id IN (#{sampleUniqueIds, typeHandler=org.apache.ibatis.type.ArrayTypeHandler})
), non_constant_genes AS ( SELECT hugo_gene_symbol FROM genetic_alteration_derived WHERE cancer_study_identifier = #{cancerStudyIdentifierB} AND profile_type = #{profileTypeB} AND hugo_gene_symbol != #{hugoGeneSymbol} AND alteration_value != '' AND alteration_value != 'NA' AND toFloat64OrNull(alteration_value) IS NOT NULL GROUP BY hugo_gene_symbol HAVING uniqExact(toFloat64OrNull(alteration_value)) > 1 ) SELECT g.entrez_gene_id AS entrezGeneId, rankCorr(r.ref_val, toFloat64OrNull(d.alteration_value)) AS spearmansCorrelation, count(*) AS numSamples FROM genetic_alteration_derived d INNER JOIN ref_values r ON d.sample_unique_id = r.sample_unique_id INNER JOIN gene g ON d.hugo_gene_symbol = g.hugo_gene_symbol WHERE d.cancer_study_identifier = #{cancerStudyIdentifierB} AND d.profile_type = #{profileTypeB} AND d.hugo_gene_symbol IN (SELECT hugo_gene_symbol FROM non_constant_genes) AND d.alteration_value != '' AND d.alteration_value != 'NA' AND toFloat64OrNull(d.alteration_value) IS NOT NULL GROUP BY g.entrez_gene_id HAVING count(*) >= 3 AND uniq(toFloat64OrNull(d.alteration_value)) > count(*) / 2 AND isFinite(spearmansCorrelation) AND abs(spearmansCorrelation) >= #{threshold} ORDER BY abs(spearmansCorrelation) DESC
